-- generated by supabase/scripts/generate-migration.ts
set check_function_bodies = off;
set client_min_messages = warning;


-- file: views/stats_situational_base.sql
-- Per-user situational ATS base at the atomic (group, user, settled pick) grain: one row per
-- placed, graded pick in a scoring round, carrying the four situational dimensions the "Your
-- edge" panel (issue #502) reads from -- primetime slot, the side backed (home/away), the
-- spread-magnitude bucket, and whether the matchup was divisional -- plus the pick's ATS
-- outcome. The per-user counterpart to league_ats_base: where that answers "did the favorite
-- cover?" league-wide, this answers "how did THIS player do?" in each situation. Every
-- stats_situational_* aggregate derives from this matview, so the panel and any future cut can
-- never compute the same record two different ways.
--
-- Classification is read off the LINE AT PICK TIME (picks.locked_spread_*), never re-derived
-- from the closing line, so it needs no re-grade -- the same choice stats_accuracy_by_line_side
-- makes. picked_spread is the locked spread stated on the team the player actually backed
-- (negative = they took the favorite); abs(picked_spread) is the line magnitude the spread
-- bucket groups by, matching league_ats_spread_buckets so the per-user cut lines up with the
-- league baseline. Buckets follow the League tab epic: pick'em (0), 1-3, 3.5-6.5, 7-9.5, 10+.
--
-- is_primetime mirrors league_ats_primetime's slot rule: a night game is one whose kickoff,
-- converted to America/New_York (DST-safe -- EDT in September, EST by January), lands on
-- Thu/Sat/Sun/Mon (dow 4/6/0/1) at hour >= 18 (6pm ET). Everything else -- Sunday afternoon,
-- international mornings, Saturday/holiday day games -- is a day game. Converting rather than
-- reading the raw UTC timestamp is what keeps an 8pm ET kickoff (stored as small-hours UTC of
-- the next day) from being misread as a day game.
--
-- is_divisional is same conference AND same division (division names like 'East' repeat across
-- conferences, so both must match), read from teams.division / teams.conference (seeded for the
-- 32 NFL teams in 0229_seed_team_divisions.sql). It is symmetric across the two sides, so it is
-- a game-level fact independent of which team the player backed. NULL when either side lacks a
-- division/conference (e.g. a non-NFL matchup) -- the divisional aggregate excludes those.
--
-- Only placed picks count (pick_id is not null): a missed pick has a settlement row but no team,
-- so it cannot be classified -- mirroring stats_accuracy_by_line_side. Non-scoring rounds
-- (ADR-0016) are excluded via w.is_scoring. Matviews can't carry RLS, so all reads are
-- service-role-only (ADR-0013); group_id leads the unique index per ADR-0002.
--
-- DROP ... CASCADE (not DROP VIEW): stats_situational_splits selects from this matview (a hard
-- pg_depend edge), so re-emitting this file drops it too -- every migration that re-emits this
-- file must also re-touch stats_situational_splits.sql so the generator bundles its recreate
-- into the same migration (same rule as league_ats_base / league_completed_standings).

drop materialized view if exists public.stats_situational_base cascade;

create materialized view public.stats_situational_base as
with settled as (
  select
    ps.group_id,
    ps.user_id,
    s.year as season_year,
    ps.game_id,
    ps.outcome,
    (p.picked_team_id = g.home_team_id) as is_home_pick,
    (g.commence_time at time zone 'America/New_York') as et,
    -- Spread stated on the side the player backed (line at pick time). locked_spread_value is
    -- NOT NULL on every settled pick (schema 0204_require_locks), the same invariant
    -- stats_accuracy_by_line_side relies on, so picked_spread is always present.
    case
      when p.picked_team_id = p.locked_spread_team_id then p.locked_spread_value
      else -p.locked_spread_value
    end as picked_spread,
    th.division as home_division,
    th.conference as home_conference,
    ta.division as away_division,
    ta.conference as away_conference
  from public.pick_settlement ps
  join public.picks p on p.id = ps.pick_id
  join public.games g on g.id = ps.game_id
  join public.weeks w on w.id = g.week_id
  join public.seasons s on s.id = w.season_id
  join public.teams th on th.id = g.home_team_id
  join public.teams ta on ta.id = g.away_team_id
  -- Non-scoring rounds (ADR-0016) never count toward stats; missed picks carry no team.
  where w.is_scoring
    and ps.pick_id is not null
)
select
  group_id,
  user_id,
  season_year,
  game_id,
  outcome,
  is_home_pick,
  (extract(dow from et) in (0, 1, 4, 6) and extract(hour from et) >= 18) as is_primetime,
  -- Spread-magnitude bucket by the picked-side line (pick'em/1-3/3.5-6.5/7-9.5/10+); mirrors
  -- league_ats_spread_buckets so the per-user cut lines up with the league baseline.
  case
    when abs(picked_spread) = 0 then 0
    when abs(picked_spread) <= 3 then 1
    when abs(picked_spread) <= 6.5 then 2
    when abs(picked_spread) <= 9.5 then 3
    else 4
  end as spread_bucket_order,
  -- Divisional matchup; NULL when either side is unclassified (non-NFL), excluded downstream.
  case
    when home_division is null or home_conference is null
      or away_division is null or away_conference is null then null
    else (home_conference = away_conference and home_division = away_division)
  end as is_divisional
from settled;

-- Unique natural key for REFRESH ... CONCURRENTLY (ADR-0013); group_id leads per ADR-0002.
-- (group_id, user_id, game_id) is the pick_settlement primary key, so it is unique here.
create unique index if not exists uq_stats_situational_base
  on public.stats_situational_base (group_id, user_id, game_id);

revoke all on public.stats_situational_base from public, anon, authenticated;
grant select on public.stats_situational_base to service_role;

-- file: views/stats_situational_splits.sql
-- Per-user situational ATS records at CAREER grain (all seasons pooled), in one long/tidy shape
-- the "Your edge" panel (issue #502) consumes uniformly: one row per (group_id, user_id,
-- dimension, bucket) with the player's decisions and win/loss/push record in that situation.
-- Career-first because the edge is meaningful day-one off the imported 2022-24 seasons, where
-- per-season situational samples are still too thin to read (the panel guards on `decisions`).
--
-- Four dimensions, all derived from stats_situational_base so the numbers can never disagree
-- with any other cut:
--   primetime  -> bucket in ('primetime','day')            -- night game vs everything else
--   home_away  -> bucket in ('home','away')                 -- which side the player backed
--   spread     -> bucket in ('pickem','1-3','3.5-6.5','7-9.5','10+')  -- line magnitude
--   divisional -> bucket in ('divisional','non_divisional') -- shared conference AND division
-- bucket_order gives the UI a stable within-dimension sort (e.g. spread ascending by magnitude).
-- Unclassifiable matchups (divisional: a side with no division/conference) are excluded from the
-- divisional dimension but still count in the others, so that dimension's buckets sum only to the
-- picks it can classify, not necessarily to the player's whole record.
--
-- accuracy = wins / (wins + losses), pushes excluded, 4 decimal places -- matching
-- stats_accuracy_by_team so ATS win% reads the same everywhere. A plain view over the
-- service_role-only base matview (no duplicated aggregation); matches that grant and carries no
-- RLS. Sorts alphabetically AFTER stats_situational_base within views/, so the generator emits
-- the base first (see the emit-order note in database.md).

create or replace view public.stats_situational_splits as
with cuts as (
  -- Primetime: night game vs day.
  select
    group_id,
    user_id,
    'primetime'::text as dimension,
    case when is_primetime then 'primetime' else 'day' end as bucket,
    case when is_primetime then 0 else 1 end as bucket_order,
    count(*)::int as decisions,
    count(*) filter (where outcome = 'win')::int as wins,
    count(*) filter (where outcome = 'loss')::int as losses,
    count(*) filter (where outcome = 'push')::int as pushes
  from public.stats_situational_base
  group by group_id, user_id, is_primetime

  union all
  -- Home/away: the side the player backed.
  select
    group_id,
    user_id,
    'home_away',
    case when is_home_pick then 'home' else 'away' end,
    case when is_home_pick then 0 else 1 end,
    count(*)::int,
    count(*) filter (where outcome = 'win')::int,
    count(*) filter (where outcome = 'loss')::int,
    count(*) filter (where outcome = 'push')::int
  from public.stats_situational_base
  group by group_id, user_id, is_home_pick

  union all
  -- Spread magnitude on the picked side.
  select
    group_id,
    user_id,
    'spread',
    (array['pickem', '1-3', '3.5-6.5', '7-9.5', '10+'])[spread_bucket_order + 1],
    spread_bucket_order,
    count(*)::int,
    count(*) filter (where outcome = 'win')::int,
    count(*) filter (where outcome = 'loss')::int,
    count(*) filter (where outcome = 'push')::int
  from public.stats_situational_base
  group by group_id, user_id, spread_bucket_order

  union all
  -- Divisional vs non-divisional; unclassifiable matchups excluded.
  select
    group_id,
    user_id,
    'divisional',
    case when is_divisional then 'divisional' else 'non_divisional' end,
    case when is_divisional then 0 else 1 end,
    count(*)::int,
    count(*) filter (where outcome = 'win')::int,
    count(*) filter (where outcome = 'loss')::int,
    count(*) filter (where outcome = 'push')::int
  from public.stats_situational_base
  where is_divisional is not null
  group by group_id, user_id, is_divisional
)
select
  group_id,
  user_id,
  dimension,
  bucket,
  bucket_order,
  decisions,
  wins,
  losses,
  pushes,
  round(wins::numeric / nullif(wins + losses, 0), 4) as accuracy
from cuts;

revoke all on public.stats_situational_splits from public, anon, authenticated;
grant select on public.stats_situational_splits to service_role;

-- file: functions/stats/refresh_leaderboard_stats.sql
-- Refresh the materialized leaderboard/stats views after a grading run (issue #191).
--
-- SECURITY DEFINER so it executes as the matview owner (postgres) -- REFRESH MATERIALIZED
-- VIEW requires ownership, and the calling service_role is not the owner. search_path is
-- pinned empty with every object schema-qualified.
--
-- CONCURRENTLY keeps each view readable by in-flight requests during the refresh and is
-- transaction-safe inside this function (unlike CREATE INDEX CONCURRENTLY, REFRESH ...
-- CONCURRENTLY does not self-manage transactions); it requires the unique index each
-- matview declares in supabase/src/views/.
--
-- Called by the server grading helpers (src/lib/server/grading.ts) after grade_game /
-- grade_week / grade_season succeed. A refresh failure is logged there but does NOT fail
-- the grade: the settlement write already committed and a stale matview self-heals on the
-- next grade. EXECUTE is granted to service_role by grants/admin_grants.sql (blanket
-- grant on all functions); the closed-by-default ACL guard strips only the PUBLIC grant.
create or replace function public.refresh_leaderboard_stats()
returns void
language plpgsql
security definer
set search_path = ''
as $$
begin
  refresh materialized view concurrently public.leaderboard_season_totals;
  refresh materialized view concurrently public.stats_season_trend;
  refresh materialized view concurrently public.stats_accuracy_by_team;
  refresh materialized view concurrently public.stats_accuracy_by_weight;
  refresh materialized view concurrently public.stats_head_to_head;
  refresh materialized view concurrently public.stats_head_to_head_alltime;
  refresh materialized view concurrently public.stats_alltime_totals;
  refresh materialized view concurrently public.stats_accuracy_by_team_alltime;
  refresh materialized view concurrently public.stats_accuracy_by_weight_alltime;
  refresh materialized view concurrently public.group_pick_consensus;
  refresh materialized view concurrently public.stats_accuracy_by_line_side;
  refresh materialized view concurrently public.stats_pick_streaks;
  -- Per-user situational ATS base (#502): pick-grain classification (primetime / home-away /
  -- spread bucket / divisional) the "Your edge" panel reads via stats_situational_splits. Driven
  -- by the same pick_settlement rows every other per-user stat is, so this is its refresh point.
  refresh materialized view concurrently public.stats_situational_base;
  -- League-wide team ATS facts (#406). Group-independent and driven by games/game_lines
  -- rather than pick_settlement, but the same grading run that settles picks is also when
  -- games go final + closing lines are captured, so this is the correct invalidation point.
  refresh materialized view concurrently public.league_ats_base;
end;
$$;

comment on function public.refresh_leaderboard_stats() is
  'Refreshes the 14 leaderboard/stats materialized views CONCURRENTLY (issues #191/#280/#294/#296/#317/#406/#502). '
  'Called after each grading run by src/lib/server/grading.ts.';
